static inline YrCamera init_camera_pos(Vector2 pos) {
    return (YrCamera){
        .pos = pos,
        .dir = (Vector2){0.0f, -1.0f},
        .horizon = 0.0f,
        .angle = 0.0f
    };
}

static inline YrCamera init_camera(void) {
    return init_camera_pos((Vector2){3.549061f, 46.84634f});
}

